  end // always @(posedge)
  FP32Multiplier mulInvLn2 (
    .io_a      (s0_x),
    .io_b      (32'h3FB8AA3B),
    .io_result (_mulInvLn2_io_result)
  );
  FP32Multiplier mulKLn2 (
    .io_a      (s2_kFp),
    .io_b      (32'h3F317218),
    .io_result (_mulKLn2_io_result)
  );
  FP32Adder subR (
    .io_a      (s2_x),
    .io_b      ({~(_mulKLn2_io_result[31]), _mulKLn2_io_result[30:0]}),
    .io_result (_subR_io_result)
  );
  FP32Adder addBias (
    .io_a      (s3_r),
    .io_b      (32'h3EB17218),
    .io_result (_addBias_io_result)
  );
  FP32Multiplier mulNorm (
    .io_a      (_addBias_io_result),
    .io_b      (32'h433738E7),
    .io_result (_mulNorm_io_result)
  );
  FP32Adder subFrac (
    .io_a      (s4_mulNorm),
    .io_b
      ({1'h1,
        _addrFp32_man_T ? 8'h0 : 8'h9E - {3'h0, _addrFp32_lz_T_90},
        _addrFp32_man_T ? 23'h0 : _addrFp32_man_T_1[30:8]}),
    .io_result (_subFrac_io_result)
  );
  FP32Adder subDiff (
    .io_a      (_GEN[(&addrFull) ? 7'h7F : addrFull + 7'h1]),
    .io_b      ({~(_GEN[addrFull][31]), _GEN[addrFull][30:0]}),
    .io_result (_subDiff_io_result)
  );
  FP32Multiplier mulInterp (
    .io_a      (s5_diff),
    .io_b      (s5_frac),
    .io_result (_mulInterp_io_result)
  );
  FP32Adder addInterp (
    .io_a      (s6_lut0),
    .io_b      (s6_interp),
    .io_result (_addInterp_io_result)
  );
  assign io_result = resultReg;
endmodule

module Int32ToFP32(
  input  [31:0] io_in,
  output [31:0] io_out
);

  wire        sign = $signed(io_in) < 32'sh0;
  wire [31:0] absVal = sign ? 32'h0 - io_in : io_in;
  wire [7:0]  _GEN =
    {{absVal[11:8], absVal[15:14]} & 6'h33, 2'h0} | {absVal[15:12], absVal[19:16]}
    & 8'h33;
  wire [18:0] _GEN_0 =
    {absVal[5:4],
     absVal[7:6],
     absVal[9:8],
     _GEN,
     absVal[19:18],
     absVal[21:20],
     absVal[23]} & 19'h55555;
  wire [3:0]  _GEN_1 = _GEN_0[18:15] | {absVal[7:6], absVal[9:8]} & 4'h5;
  wire [7:0]  _GEN_2 = _GEN_0[14:7] | _GEN & 8'h55;
  wire [3:0]  _GEN_3 = {_GEN_0[2:0], 1'h0} | {absVal[23:22], absVal[25:24]} & 4'h5;
  wire [4:0]  leadingZeros =
    absVal[31]
      ? 5'h0
      : absVal[30]
          ? 5'h1
          : absVal[29]
              ? 5'h2
              : absVal[28]
                  ? 5'h3
                  : absVal[27]
                      ? 5'h4
                      : absVal[26]
                          ? 5'h5
                          : absVal[25]
                              ? 5'h6
                              : _GEN_3[0]
                                  ? 5'h7
                                  : _GEN_3[1]
                                      ? 5'h8
                                      : _GEN_3[2]
                                          ? 5'h9
                                          : _GEN_3[3]
                                              ? 5'hA
                                              : absVal[20]
                                                  ? 5'hB
                                                  : absVal[19]
                                                      ? 5'hC
                                                      : _GEN_0[5] | absVal[18]
                                                          ? 5'hD
                                                          : _GEN[1]
                                                              ? 5'hE
                                                              : _GEN_2[0]
                                                                  ? 5'hF
                                                                  : _GEN_2[1]
                                                                      ? 5'h10
                                                                      : _GEN_2[2]
                                                                          ? 5'h11
                                                                          : _GEN_2[3]
                                                                              ? 5'h12
                                                                              : _GEN_2[4]
                                                                                  ? 5'h13
                                                                                  : _GEN_2[5]
                                                                                      ? 5'h14
                                                                                      : _GEN_2[6]
                                                                                          ? 5'h15
                                                                                          : _GEN_2[7]
                                                                                              ? 5'h16
                                                                                              : _GEN_1[0]
                                                                                                  ? 5'h17
                                                                                                  : _GEN_1[1]
                                                                                                      ? 5'h18
                                                                                                      : _GEN_1[2]
                                                                                                          ? 5'h19
                                                                                                          : _GEN_1[3]
                                                                                                              ? 5'h1A
                                                                                                              : absVal[4]
                                                                                                                  ? 5'h1B
                                                                                                                  : absVal[3]
                                                                                                                      ? 5'h1C
                                                                                                                      : absVal[2]
                                                                                                                          ? 5'h1D
                                                                                                                          : {4'hF,
                                                                                                                             ~(absVal[1])};
  wire [62:0] normalized = {31'h0, absVal} << leadingZeros;
  assign io_out =
    {sign,
     absVal == 32'h0
       ? 31'h0
       : {{2'h0, 6'h1F - {1'h0, leadingZeros}} + 8'h7F, normalized[30:8]}};
endmodule

