module EMLUnit(
  input         clock,
                reset,
  input  [31:0] io_x,
                io_y,
  output [31:0] io_result
);

  wire [31:0] _lnUnit_io_result;
  wire [31:0] _expUnit_io_result;
  reg  [31:0] lnDelayed;
  reg  [31:0] lnDelayed2;
  reg  [31:0] lnDelayed3;
  reg  [31:0] lnDelayed4;
  always @(posedge clock) begin
    lnDelayed <= _lnUnit_io_result;
    lnDelayed2 <= lnDelayed;
    lnDelayed3 <= lnDelayed2;
    lnDelayed4 <= lnDelayed3;
  end // always @(posedge)
  ExpApprox expUnit (
    .clock      (clock),
    .io_operand (io_x),
    .io_result  (_expUnit_io_result)
  );
  LnApprox lnUnit (
    .clock      (clock),
    .io_operand (io_y),
    .io_result  (_lnUnit_io_result)
  );
  FP32Adder subUnit (
    .io_a      (_expUnit_io_result),
    .io_b      ({~(lnDelayed4[31]), lnDelayed4[30:0]}),
    .io_result (io_result)
  );
endmodule

